func generateRandomState() (string, error) {
	b := make([]byte, 32)
	_, err := rand.Read(b)
	if err != nil {
		return "", fmt.Errorf("failed to generate random state: %w", err)
	}
	return base64.URLEncoding.EncodeToString(b), nil
}

// validateRedirectPath validates that the redirect path is safe to use.
// It only allows relative paths on the same application domain.
func validateRedirectPath(redirectPath string) (string, error) {
	if redirectPath == "" {
		return "/", nil
	}

	parsed, err := url.Parse(redirectPath)
	if err != nil {
		return "", fmt.Errorf("invalid redirect path: %w", err)
	}

	// If it's a relative path (no scheme and no host), allow it as long as
	// it doesn't try to do a protocol-relative redirect.
	if parsed.Scheme == "" && parsed.Host == "" {
		// Ensure the path doesn't start with "//" (protocol-relative URL)
		// or contain backslashes which some browsers interpret as slashes.
		cleaned := strings.ReplaceAll(redirectPath, "\\", "/")
		if strings.HasPrefix(cleaned, "//") {
			return "", fmt.Errorf("invalid redirect path: protocol-relative URLs are not allowed")
		}
		// Ensure it starts with "/"
		if !strings.HasPrefix(redirectPath, "/") {
			redirectPath = "/" + redirectPath
		}
		return redirectPath, nil
	}

	// If it's an absolute URL, validate the host is in our allowlist
	if parsed.Scheme != "https" {
		return "", fmt.Errorf("invalid redirect path: only HTTPS URLs are allowed")
	}

	if !allowedRedirectHosts[parsed.Hostname()] {
		return "", fmt.Errorf("invalid redirect path: host %q is not allowed", parsed.Hostname())
	}

	return parsed.Path, nil
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Generate a cryptographically secure random state to prevent CSRF
	state, err := generateRandomState()
	if err != nil {
