	authURL := OAuthConfig.AuthCodeURL(state, oauth2.AccessTypeOnline)

	// Set the state in a cookie for later CSRF validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
