	parsed, err := url.Parse(redirectPath)
	if err != nil {
		return fmt.Errorf("invalid redirect path: %w", err)
	}

	// Reject absolute URLs with a different host (prevent open redirect)
	if parsed.IsAbs() {
		parsedBase, err := url.Parse(OAuthConfig.RedirectURL)
		if err != nil {
			return fmt.Errorf("invalid base redirect URL: %w", err)
		}
		if !strings.EqualFold(parsed.Host, parsedBase.Host) || !strings.EqualFold(parsed.Scheme, parsedBase.Scheme) {
			return fmt.Errorf("redirect to external host is not allowed")
		}
	}

	// Ensure the path starts with / (relative path) and doesn't contain protocol-relative URLs
	cleanPath := parsed.Path
	if !strings.HasPrefix(cleanPath, "/") {
		return fmt.Errorf("redirect path must be a relative path starting with /")
	}

	// Reject paths that could be used for open redirects
	if strings.HasPrefix(cleanPath, "//") {
		return fmt.Errorf("invalid redirect path format")
	}

	return nil
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Generate a cryptographically secure random state to prevent CSRF
	state, err := generateRandomState()
	if err != nil {
		return "", fmt.Errorf("failed to generate state: %w", err)
	}

