)

var OAuthConfig = &oauth2.Config{
	ClientID:     "your-client-id",
	ClientSecret: "your-client-secret",
	RedirectURL:  "https://yourapp.com/callback",
	Scopes:       []string{"openid", "profile", "email"},
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/authorize",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Generate a random state parameter to protect against CSRF attacks
	stateBytes := make([]byte, 32)
	_, err := rand.Read(stateBytes)
	if err != nil {
		return "", fmt.Errorf("failed to generate state: %w", err)
	}
	state := base64.URLEncoding.EncodeToString(stateBytes)

	// Store the state and redirect path in a cookie so we can verify it on callback
	stateCookie := &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		Path:     "/",
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
	}
	http.SetCookie(w, stateCookie)

	// Store the redirect path in a cookie so we know where to redirect after auth
	redirectCookie := &http.Cookie{
		Name:     "oauth_redirect",
		Value:    redirectPath,
		Path:     "/",
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
	}
	http.SetCookie(w, redirectCookie)

	// Create a copy of the config with the custom redirect URL if provided
	config := *OAuthConfig
	if redirectPath != "" {
		config.RedirectURL = redirectPath
	}

	// Generate the authorization URL with the state parameter
	authURL := config.AuthCodeURL(state, oauth2.AccessTypeOnline)

	return authURL, nil
}

func main() {
	http.HandleFunc("/login", func(w http.ResponseWriter, r *http.Request) {
		redirectPath := r.URL.Query().Get("redirect")
		if redirectPath == "" {
			redirectPath = OAuthConfig.RedirectURL
		}

		session, _ := r.Cookie("session")

		authURL, err := GenerateAuthURL(redirectPath, session, w, r)
		if err != nil {
			http.Error(w, "Failed to generate auth URL", http.StatusInternalServerError)
			return
		}

		http.Redirect(w, r, authURL, http.StatusFound)
	})

	http.HandleFunc("/callback", func(w http.ResponseWriter, r *http.Request) {
		fmt.Fprintf(w, "OAuth callback received")
	})

	fmt.Println("Server starting on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Printf("Server failed: %v\n", err)
	}
}

